func TestNoRefreshCommands_SuperhumanSkipList(t *testing.T) {
	want := []string{
		"sync", "auth", "doctor", "help", "version", "completion",
		"agent-context", "profile", "feedback", "which",
	}
	if len(noRefreshCommands) != len(want) {
		t.Fatalf("skip list length = %d want %d (%v)", len(noRefreshCommands), len(want), noRefreshCommands)
	}
	for _, name := range want {
		if _, ok := noRefreshCommands[name]; !ok {
			t.Errorf("noRefreshCommands missing %q", name)
		}
	}
	if _, ok := noRefreshCommands["bootstrap"]; ok {
		t.Fatal("bootstrap should not be in the canonical Superhuman auto-refresh skip list")
	}
}

func TestShouldSkipAutoRefresh_TopLevelAndAncestors(t *testing.T) {
	for name := range noRefreshCommands {
		t.Run("top/"+name, func(t *testing.T) {
			cmd := &cobra.Command{Use: name}
			if !shouldSkipAutoRefresh(cmd) {
				t.Fatalf("%q should skip", name)
			}
		})
	}

	root := &cobra.Command{Use: "superhuman-pp-cli"}
	authCmd := &cobra.Command{Use: "auth"}
	loginCmd := &cobra.Command{Use: "login"}
	authCmd.AddCommand(loginCmd)
	root.AddCommand(authCmd)
	if !shouldSkipAutoRefresh(loginCmd) {
		t.Fatal("auth login should skip via ancestor walking")
	}

	threads := &cobra.Command{Use: "threads"}
	list := &cobra.Command{Use: "list"}
	threads.AddCommand(list)
	root.AddCommand(threads)
	if shouldSkipAutoRefresh(list) {
		t.Fatal("threads list should not skip auto-refresh")
	}
}

func TestAutoRefreshOptOutPrecedence(t *testing.T) {
	cases := []struct {
		name       string
		flagSet    bool
		flagValue  bool
		profileSet bool
		profileVal bool
		env        string
		want       bool
	}{
		{name: "flag true beats profile false env empty", flagSet: true, flagValue: true, profileSet: true, profileVal: false, env: "", want: true},
		{name: "flag false beats profile true", flagSet: true, flagValue: false, profileSet: true, profileVal: true, env: "", want: false},
		{name: "flag false beats env true", flagSet: true, flagValue: false, env: "1", want: false},
		{name: "profile true beats env empty", profileSet: true, profileVal: true, env: "", want: true},
		{name: "profile false beats env true", profileSet: true, profileVal: false, env: "yes", want: false},
		{name: "env true when no flag or profile", env: "true", want: true},
		{name: "default on", env: "", want: false},
	}
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			t.Setenv(autoRefreshEnvVar, tc.env)
			flags := &rootFlags{
				noRefresh:           tc.flagValue || (tc.profileSet && tc.profileVal),
				profileNoRefreshSet: tc.profileSet,
				profileNoRefresh:    tc.profileVal,
			}
			cmd := autoRefreshTestCmd(flags)
			if tc.flagSet {
				if err := cmd.Root().PersistentFlags().Set("no-refresh", boolString(tc.flagValue)); err != nil {
					t.Fatalf("set no-refresh: %v", err)
				}
			}
			if got := autoRefreshOptedOut(cmd, flags); got != tc.want {
				t.Fatalf("autoRefreshOptedOut = %v want %v", got, tc.want)
			}
		})
	}
}

