func TestDetectRefreshPlan(t *testing.T) {
	t.Run("empty", func(t *testing.T) {
		home := t.TempDir()
		t.Setenv("HOME", home)
		t.Setenv("SUPERHUMAN_JWT", "")
		flags := &rootFlags{configPath: configPathUnder(t, home)}
		if got := detectRefreshPlan(flags); !got.empty() {
			t.Fatalf("plan = %+v want empty", got)
		}
	})

	t.Run("cache only", func(t *testing.T) {
		home := t.TempDir()
		t.Setenv("HOME", home)
		t.Setenv("SUPERHUMAN_JWT", "jwt-test")
		flags := &rootFlags{configPath: configPathUnder(t, home)}
		got := detectRefreshPlan(flags)
		if !got.cache || got.gmail {
			t.Fatalf("plan = %+v want cache-only", got)
		}
	})

	t.Run("gmail only", func(t *testing.T) {
		home := t.TempDir()
		t.Setenv("HOME", home)
		t.Setenv("SUPERHUMAN_JWT", "")
		configPath, tokenStorePath := withConfigPath(t)
		writeConfigPointingAt(t, configPath, "http://unused", "user@example.com")
		seedGmailAccount(t, tokenStorePath, "user@example.com")
		flags := &rootFlags{configPath: configPath}
		got := detectRefreshPlan(flags)
		if got.cache || !got.gmail {
			t.Fatalf("plan = %+v want gmail-only", got)
		}
	})

	t.Run("both", func(t *testing.T) {
		t.Setenv("SUPERHUMAN_JWT", "jwt-test")
		configPath, tokenStorePath := withConfigPath(t)
		writeConfigPointingAt(t, configPath, "http://unused", "user@example.com")
		seedGmailAccount(t, tokenStorePath, "user@example.com")
		flags := &rootFlags{configPath: configPath}
		got := detectRefreshPlan(flags)
		if !got.cache || !got.gmail {
			t.Fatalf("plan = %+v want both", got)
		}
	})
}

func TestRefreshPlanRun_PerSurfaceOutcomes(t *testing.T) {
	prevCache := runSuperhumanBackendRefresh
	prevGmail := runGmailHistoryRefresh
	t.Cleanup(func() {
		runSuperhumanBackendRefresh = prevCache
		runGmailHistoryRefresh = prevGmail
	})
	runSuperhumanBackendRefresh = func(context.Context, *rootFlags) (BackendSyncResult, error) {
		return BackendSyncResult{TotalRecords: 47, Duration: 520 * time.Millisecond}, nil
	}
	runGmailHistoryRefresh = func(context.Context, *rootFlags) (GmailHistoryRefreshResult, error) {
		return GmailHistoryRefreshResult{RowsAffected: 12, HistoryID: "h-2", Duration: 1200 * time.Millisecond}, nil
	}

	results := (refreshPlan{cache: true, gmail: true}).run(context.Background(), &rootFlags{})
	if len(results) != 2 {
		t.Fatalf("len(results) = %d want 2", len(results))
	}
	if results[0].surface != refreshSurfaceCache || !results[0].ok || results[0].rows != 47 {
		t.Fatalf("cache result = %+v", results[0])
	}
	if results[1].surface != refreshSurfaceGmail || !results[1].ok || results[1].rows != 12 {
		t.Fatalf("gmail result = %+v", results[1])
	}

	runGmailHistoryRefresh = func(context.Context, *rootFlags) (GmailHistoryRefreshResult, error) {
		return GmailHistoryRefreshResult{Duration: 10 * time.Millisecond}, errors.New("HTTP 401: unauthorized")
	}
	results = (refreshPlan{gmail: true}).run(context.Background(), &rootFlags{})
	if len(results) != 1 || results[0].ok || results[0].err == nil {
		t.Fatalf("gmail failure result = %+v", results)
	}
	if got := formatRefreshFragment(results[0]); got != "gmail=failed (run 'auth login --chrome' to re-authenticate)" {
		t.Fatalf("gmail failure fragment = %q", got)
	}
}

