func TestEmitProvenanceLine_FailureAndEmpty(t *testing.T) {
	var buf bytes.Buffer
	emitProvenanceLine(&buf, []refreshResult{
		{surface: refreshSurfaceCache, ok: false, duration: 30 * time.Millisecond, err: errors.New("keychain unavailable\nmore detail")},
	})
	if got, want := buf.String(), "auto-refresh: cache=failed (keychain unavailable)\n"; got != want {
		t.Fatalf("failure line = %q want %q", got, want)
	}
	buf.Reset()
	emitProvenanceLine(&buf, nil)
	if buf.Len() != 0 {
		t.Fatalf("empty results should not emit, got %q", buf.String())
	}
}

