func TestShortErrAndCompactErr(t *testing.T) {
	if got := shortErr(nil); got != "" {
		t.Fatalf("shortErr(nil) = %q", got)
	}
	long := strings.Repeat("x", 200)
	if got := shortErr(errors.New(long)); len(got) > 80 || !strings.HasSuffix(got, "...") {
		t.Fatalf("shortErr long = %q", got)
	}
	if got := shortErr(errors.New("first\nsecond")); got != "first" {
		t.Fatalf("shortErr newline = %q", got)
	}
	if got := compactErr(errors.New("GET /users/me/history returned HTTP 401: unauthorized")); got != "run 'auth login --chrome' to re-authenticate" {
		t.Fatalf("compactErr 401 = %q", got)
	}
}

