func TestAgentContext_AutoRefreshContract(t *testing.T) {
	ctx := buildAutoRefreshContext()
	if ctx.Default != "on" || ctx.Flag != "--no-refresh" || ctx.Env != autoRefreshEnvVar || ctx.ProfileField != "no-refresh" {
		t.Fatalf("contract header = %+v", ctx)
	}
	if !equalStringSlice(ctx.Surfaces, []string{"cache", "gmail"}) {
		t.Fatalf("surfaces = %v want [cache gmail]", ctx.Surfaces)
	}
	if !equalStringSlice(ctx.SkipList, sortedNoRefreshCommands()) {
		t.Fatalf("skip list = %v want %v", ctx.SkipList, sortedNoRefreshCommands())
	}
}

