func seedGmailAccount(t *testing.T, tokenStorePath, email string) {
	t.Helper()
	store := auth.NewStoreAt(tokenStorePath)
	now := time.Now().UnixMilli()
	if _, err := store.Upsert(email, auth.AccountTokens{
		Type:        "google",
		AccessToken: "ya29.test",
		UserID:      "gid-001",
		SuperhumanToken: auth.SuperhumanToken{
			Token:   "",
			Expires: now + int64(time.Hour.Milliseconds()),
		},
		LastUsedAt: now,
	}); err != nil {
		t.Fatalf("seed gmail account: %v", err)
	}
}

func configPathUnder(t *testing.T, home string) string {
	t.Helper()
	return home + "/.config/superhuman-pp-cli/config.toml"
}

func equalStringSlice(a, b []string) bool {
	if len(a) != len(b) {
		return false
	}
	for i := range a {
		if a[i] != b[i] {
			return false
		}
	}
	return true
}
